138→function validateTapParams(params: TapParams): ToolTextResult | null {
139→  const hasX = params.x !== undefined;
140→  const hasY = params.y !== undefined;
141→  const hasSelector = params.id !== undefined || params.label !== undefined;
142→
143→  if (hasX !== hasY) {
144→    return {
145→      content: [{ type: "text", text: "Both x and y must be provided together." }],
146→      isError: true,
147→    };
148→  }
149→
150→  if (hasX && hasSelector) {
151→    return {
152→      content: [{ type: "text", text: "Provide either x/y coordinates or id/label, not both." }],
153→      isError: true,
154→    };
155→  }
156→
157→  if (!hasX && !params.id && !params.label) {
158→    return {
159→      content: [{ type: "text", text: "Provide either x/y coordinates, id, or label." }],
160→      isError: true,
161→    };
162→  }
163→
164→  return null;
165→}
