308→      if (validationError) return validationError;
309→
310→      const target = resolveUnifiedTargetArgs(params as UnifiedTargetParams);
311→      if (!Array.isArray(target)) return target;
312→      return await runNative(buildTapArgs(target, params as TapParams));
313→    }
314→  );
315→
316→  server.tool(
317→    "type_text",
318→    "Type text into the target app.",
319→    { ...unifiedTargetSchema, ...typeSchema },
320→    async (params) => {
321→      const validationError = validateTypeParams(params as TypeParams);
322→      if (validationError) return validationError;
323→
324→      const target = resolveUnifiedTargetArgs(params as UnifiedTargetParams);
325→      if (!Array.isArray(target)) return target;
326→
327→      const built = buildTypeArgs(target, params as TypeParams);
328→      return await runNative(built.args, { stdinText: built.stdinText });
329→    }
330→  );
331→
332→  server.tool(
333→    "swipe",
334→    "Perform swipe gesture in the target app.",
335→    { ...unifiedTargetSchema, ...swipeSchema },
336→    async (params) => {
337→      const target = resolveUnifiedTargetArgs(params as UnifiedTargetParams);
338→      if (!Array.isArray(target)) return target;
339→      return await runNative(buildSwipeArgs(target, params as SwipeParams));
340→    }
341→  );
342→
343→  server.tool(
344→    "scroll",
345→    "Send scroll wheel events to the target app.",
346→    { ...unifiedTargetSchema, ...scrollSchema },
347→    async (params) => {
348→      const target = resolveUnifiedTargetArgs(params as UnifiedTargetParams);
349→      if (!Array.isArray(target)) return target;
350→      return await runNative(buildScrollArgs(target, params as ScrollParams));
351→    }
352→  );
353→
354→  server.tool(
355→    "drag_drop",
356→    "Drag and drop in the target app.",
357→    { ...unifiedTargetSchema, ...dragDropSchema },
358→    async (params) => {
359→      const target = resolveUnifiedTargetArgs(params as UnifiedTargetParams);
360→      if (!Array.isArray(target)) return target;
361→      return await runNative(buildDragDropArgs(target, params as DragDropParams));
