523→    var totalNodes = 0
524→    var emitted = 0
525→
526→    while let current = stack.popLast() {
527→        let element = current.element
528→        let depth = current.depth
529→
530→        // Apply filters
531→        if options.roleFilter != nil || options.visibleOnly {
532→            let attrs = copyMultipleAttributes(element, [kAXRoleAttribute as String, "AXFrame"])
533→            if let roleFilter = options.roleFilter {
534→                if let roleRef = attrs[kAXRoleAttribute as String], let role = stringFromCFTypeRef(roleRef) {
535→                    if role != roleFilter {
536→                        // Still traverse children even if this node doesn't match
537→                        if depth < options.maxDepth {
538→                            let children = Children(element)
539→                            for child in children.reversed() {
540→                                stack.append((child, depth + 1))
541→                            }
542→                        }
543→                        continue
544→                    }
545→                } else {
546→                    if depth < options.maxDepth {
547→                        let children = Children(element)
548→                        for child in children.reversed() {
549→                            stack.append((child, depth + 1))
550→                        }
551→                    }
552→                    continue
553→                }
554→            }
555→            if options.visibleOnly, let screenBounds = options.screenBounds {
556→                if let frameRef = attrs["AXFrame"], let frame = frameFromCFTypeRef(frameRef) {
557→                    if !screenBounds.intersects(frame) {
558→                        if depth < options.maxDepth {
559→                            let children = Children(element)
560→                            for child in children.reversed() {
561→                                stack.append((child, depth + 1))
562→                            }
563→                        }
564→                        continue
565→                    }
566→                }
567→            }
568→        }
569→
570→        totalNodes += 1
571→        let prefix = String(repeating: "  ", count: depth)
572→
573→        // Pagination: only emit nodes within [offset, offset+limit)
574→        if totalNodes > options.offset && emitted < options.limit {
575→            if options.summary {
576→                let children = Children(element)
577→                if let description = describeAccessibilityElement(element) {
578→                    if !children.isEmpty {
579→                        lines.append("\(prefix)- \(description) [\(children.count) children]")
580→                    } else {
581→                        lines.append("\(prefix)- \(description)")
582→                    }
583→                }
584→                emitted += 1
585→                // In summary mode, don't recurse into children
586→                continue
587→            } else {
588→                if let description = describeAccessibilityElement(element) {
589→                    lines.append("\(prefix)- \(description)")
590→                } else {
591→                    lines.append("\(prefix)- [hidden: no accessible content]")
592→                }
593→                emitted += 1
