600→                        let childTexts = getElementTextValues(child)
601→                        return childTexts.isEmpty
602→                    }.count
603→                    if unlabeledCount > 0 && unlabeledCount == tabChildren.count {
604→                        let hint = "\(prefix)  [Tab bar with \(tabChildren.count) unlabeled items - use tap_tab with index 0..\(tabChildren.count - 1)]"
605→                        lines.append(hint)
606→                    }
607→                }
608→            }
609→        }
610→
611→        if depth >= options.maxDepth {
612→            continue
613→        }
614→
615→        let children = Children(element)
616→        for child in children.reversed() {
617→            stack.append((child, depth + 1))
