449→func describeAccessibilityElement(_ element: UIElement, includeEmpty: Bool = true) -> String? {
450→    let attrs = copyMultipleAttributes(element, describeAttributes)
451→    var parts: [String] = []
452→
453→    let role: String
454→    if let roleRef = attrs[kAXRoleAttribute as String], let s = stringFromCFTypeRef(roleRef), !s.isEmpty {
455→        role = s
456→    } else {
457→        role = "unknown"
458→    }
459→    parts.append("role=\(role)")
460→
461→    if let ref = attrs[kAXSubroleAttribute as String], let s = stringFromCFTypeRef(ref), !s.isEmpty {
462→        parts.append("subrole=\(s)")
463→    }
464→
465→    if let ref = attrs["AXIdentifier"], let s = stringFromCFTypeRef(ref), !s.isEmpty {
466→        parts.append("id=\(truncateText(s))")
467→    }
468→
469→    var textSources: [String] = []
470→    let textKeys: [(String, String?)] = [
471→        ("AXLabel", nil),
472→        (kAXTitleAttribute as String, nil),
473→        (kAXDescriptionAttribute as String, nil),
474→        (kAXValueAttribute as String, nil),
475→        (kAXHelpAttribute as String, nil),
476→        ("AXPlaceholderValue", "placeholder:"),
477→    ]
478→    for (key, prefix) in textKeys {
479→        if let ref = attrs[key], let s = stringFromCFTypeRef(ref), !s.isEmpty {
480→            textSources.append(prefix != nil ? "\(prefix!)\(s)" : s)
481→        }
482→    }
483→
484→    let uniqueTexts = Array(Set(textSources)).filter { !$0.isEmpty }
485→
486→    if !uniqueTexts.isEmpty {
487→        let combinedText = uniqueTexts.joined(separator: " | ")
488→        parts.append("text=\(truncateText(combinedText))")
489→    }
490→
491→    if let ref = attrs[kAXEnabledAttribute as String], let s = stringFromCFTypeRef(ref) {
492→        if s.lowercased() == "false" || s == "0" {
493→            parts.append("enabled=false")
494→        }
495→    }
496→
497→    if let ref = attrs["AXSelected"], let s = stringFromCFTypeRef(ref) {
498→        if s.lowercased() == "true" || s == "1" {
499→            parts.append("selected=true")
500→        }
501→    }
502→
503→    if let ref = attrs["AXFrame"], let frame = frameFromCFTypeRef(ref) {
504→        let frameText = "frame=(x:\(formatFloat(frame.origin.x)),y:\(formatFloat(frame.origin.y)),w:\(formatFloat(frame.size.width)),h:\(formatFloat(frame.size.height)))"
505→        parts.append(frameText)
506→    }
507→
508→    if !includeEmpty && uniqueTexts.isEmpty {
509→        if attrs["AXIdentifier"] == nil || (stringFromCFTypeRef(attrs["AXIdentifier"]!) ?? "").isEmpty {
510→            let children = Children(element)
511→            if children.isEmpty {
512→                return nil
513→            }
514→        }
515→    }
516→
517→    return parts.joined(separator: " ")
518→}
