128→func handleGesture(_ parsed: ParsedOptions) throws -> Int32 {
129→    let target = try resolveTarget(from: parsed)
130→    try requireSimulatorOnly(target)
131→    guard let preset = parsed.positionals.first else {
132→        throw NativeError.invalidArguments("gesture requires a preset name.")
133→    }
134→    let preDelay = try optionalDoubleOption("--pre-delay", from: parsed) ?? 0
135→    let postDelay = try optionalDoubleOption("--post-delay", from: parsed) ?? 0
136→    let duration = try optionalDoubleOption("--duration", from: parsed)
137→    let screenWidth = try optionalDoubleOption("--screen-width", from: parsed)
138→    let screenHeight = try optionalDoubleOption("--screen-height", from: parsed)
139→    try ensureAccessibilityTrusted()
140→    try activateTarget(target)
141→    let bounds = simulatorContentBounds()
142→    let width = screenWidth ?? Double(bounds?.width ?? 0)
143→    let height = screenHeight ?? Double(bounds?.height ?? 0)
144→    if width <= 0 || height <= 0 {
145→        throw NativeError.commandFailed("Unable to determine simulator content size; provide screenWidth/screenHeight.")
146→    }
147→    let start: CGPoint
148→    let end: CGPoint
149→    switch preset {
150→    case "scroll-up":
151→        start = try pointInSimulatorContent(x: width * 0.5, y: height * 0.7)
152→        end = try pointInSimulatorContent(x: width * 0.5, y: height * 0.3)
153→    case "scroll-down":
154→        start = try pointInSimulatorContent(x: width * 0.5, y: height * 0.3)
155→        end = try pointInSimulatorContent(x: width * 0.5, y: height * 0.7)
156→    case "scroll-left":
157→        start = try pointInSimulatorContent(x: width * 0.7, y: height * 0.5)
158→        end = try pointInSimulatorContent(x: width * 0.3, y: height * 0.5)
159→    case "scroll-right":
160→        start = try pointInSimulatorContent(x: width * 0.3, y: height * 0.5)
161→        end = try pointInSimulatorContent(x: width * 0.7, y: height * 0.5)
162→    case "swipe-from-left-edge":
163→        start = try pointInSimulatorContent(x: width * 0.05, y: height * 0.5)
164→        end = try pointInSimulatorContent(x: width * 0.6, y: height * 0.5)
165→    case "swipe-from-right-edge":
166→        start = try pointInSimulatorContent(x: width * 0.95, y: height * 0.5)
167→        end = try pointInSimulatorContent(x: width * 0.4, y: height * 0.5)
168→    case "swipe-from-top-edge":
169→        start = try pointInSimulatorContent(x: width * 0.5, y: height * 0.05)
170→        end = try pointInSimulatorContent(x: width * 0.5, y: height * 0.6)
171→    case "swipe-from-bottom-edge":
172→        start = try pointInSimulatorContent(x: width * 0.5, y: height * 0.95)
173→        end = try pointInSimulatorContent(x: width * 0.5, y: height * 0.4)
174→    default:
175→        throw NativeError.invalidArguments("Unsupported gesture preset: \(preset)")
176→    }
177→    if preDelay > 0 {
178→        Thread.sleep(forTimeInterval: preDelay)
179→    }

